const config: runtime.GetPrismaClientConfig = {
  "previewFeatures": [],
  "clientVersion": "7.4.2",
  "engineVersion": "94a226be1cf2967af2541cca5529f0f7ba866919",
  "activeProvider": "postgresql",
  "inlineSchema": "// https://supabase.com/partners/integrations/prisma\n\n// NOTE: \n// I do not use database of Supabase, I use my own database with prisma to save data locally.\n// I only use Supabase for authentication (Google login). You can use Supabase for database as well.\n// Supabase Storage is used for file uploads (avatars, images, etc.)\n\ngenerator client {\n  provider = \"prisma-client\"\n  output   = \"./generated/prisma\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  schemas  = [\"public\"]\n}\n\n// ╔══════════════════════════════════════════════════════════════╗\n// ║                          ENUMS                              ║\n// ╚══════════════════════════════════════════════════════════════╝\n\n/// Vai trò trên web - quyền hạn hệ thống\n/// ADMIN: Toàn quyền quản trị\n/// COLLABORATOR: Cộng tác viên - được đăng bài, quản lý sự kiện\n/// MEMBER: Thành viên - tự sửa thông tin cá nhân, viết bài chờ duyệt\n/// GUEST: Đăng nhập bình thường, chưa được xác nhận thành viên\nenum WebRole {\n  ADMIN\n  COLLABORATOR\n  MEMBER\n  GUEST\n\n  @@schema(\"public\")\n}\n\n/// Chức vụ trong CLB\n/// Phản ánh cơ cấu tổ chức: Chủ nhiệm > Phó CN > Trưởng ban > Phó ban > Thành viên ban\n/// Ngoài ra còn: Cộng tác viên, Giảng viên cố vấn\nenum ClubPosition {\n  PRESIDENT // Chủ nhiệm CLB\n  VICE_PRESIDENT // Phó chủ nhiệm CLB\n  DEPARTMENT_LEADER // Trưởng ban\n  DEPARTMENT_VICE_LEADER // Phó ban\n  DEPARTMENT_MEMBER // Thành viên ban\n  COLLABORATOR // Cộng tác viên\n  ADVISOR // Giảng viên cố vấn\n\n  @@schema(\"public\")\n}\n\n/// Trạng thái bài viết - workflow duyệt bài\nenum PostStatus {\n  DRAFT // Bản nháp - chưa gửi duyệt\n  PENDING_REVIEW // Đang chờ duyệt\n  PUBLISHED // Đã xuất bản\n  ARCHIVED // Đã lưu trữ\n  REJECTED // Bị từ chối\n\n  @@schema(\"public\")\n}\n\n/// Trạng thái sự kiện\nenum EventStatus {\n  UPCOMING // Sắp diễn ra\n  ONGOING // Đang diễn ra\n  COMPLETED // Đã hoàn thành\n  CANCELLED // Đã hủy\n\n  @@schema(\"public\")\n}\n\n/// Loại thành tựu\nenum AchievementType {\n  INDIVIDUAL // Cá nhân (Olympic, thi đấu)\n  TEAM // Nhóm dự án\n  CLUB // Toàn CLB (CLB xuất sắc)\n\n  @@schema(\"public\")\n}\n\n/// Phân loại sự kiện\nenum EventType {\n  ACADEMIC // Tổ chức cuộc thi học thuật\n  MEMBER_ACTIVITY // Hoạt động thành viên\n  VOLUNTEER // Hoạt động tình nguyện\n  SEMINAR // Hội thảo / Seminar\n  OTHER // Khác\n\n  @@schema(\"public\")\n}\n\n// ╔══════════════════════════════════════════════════════════════╗\n// ║                     SITE SETTINGS                           ║\n// ╚══════════════════════════════════════════════════════════════╝\n\n/// Cài đặt trang web - Lưu cấu hình chung dạng key-value\n/// VD: site_title, site_description, site_short_description, site_logo, ...\nmodel SiteSetting {\n  id          String   @id @default(cuid())\n  key         String   @unique // VD: \"site_title\", \"site_description\"\n  value       String // Giá trị cài đặt\n  description String? // Mô tả setting này dùng làm gì\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  @@schema(\"public\")\n}\n\n/// Thông báo hiển thị trên AnnouncementBar\n/// Hỗ trợ thời hạn (startAt/endAt), nút CTA tuỳ chỉnh, màu nền tuỳ chỉnh\nmodel Announcement {\n  id        String    @id @default(cuid())\n  content   String // Nội dung thông báo\n  linkUrl   String? // URL nút CTA (VD: \"/auth\")\n  linkLabel String? // Text nút CTA (VD: \"Đăng ký ngay\")\n  bgColor   String? // CSS gradient/color\n  isActive  Boolean   @default(true)\n  startAt   DateTime  @default(now())\n  endAt     DateTime? // Null = vô thời hạn\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@schema(\"public\")\n}\n\n/// Nội dung trang chủ - key-value cho hero image, intro image, stats...\nmodel HomepageSection {\n  id       String  @id @default(cuid())\n  key      String  @unique // \"hero_image\", \"intro_image\", \"hero_bg\", ...\n  value    String // URL hoặc text\n  type     String  @default(\"text\") // \"text\", \"image\", \"json\"\n  order    Int     @default(0)\n  isActive Boolean @default(true)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@schema(\"public\")\n}\n\n/// Câu hỏi thường gặp - quản lý FAQ từ admin (song ngữ)\nmodel FaqItem {\n  id         String  @id @default(cuid())\n  questionVi String // Câu hỏi tiếng Việt\n  answerVi   String // Câu trả lời tiếng Việt\n  questionEn String  @default(\"\") // Câu hỏi tiếng Anh\n  answerEn   String  @default(\"\") // Câu trả lời tiếng Anh\n  order      Int     @default(0)\n  isActive   Boolean @default(true)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@schema(\"public\")\n}\n\n/// Ảnh gallery trang chủ - quản lý từ admin\nmodel GalleryImage {\n  id       String  @id @default(cuid())\n  url      String // Supabase Storage URL\n  caption  String?\n  order    Int     @default(0)\n  isActive Boolean @default(true)\n\n  createdAt DateTime @default(now())\n\n  @@schema(\"public\")\n}\n\n/// Liên kết ngoài - hiển thị ở footer, quản lý từ admin\nmodel ExternalLink {\n  id       String  @id @default(cuid())\n  label    String // Tên hiển thị (VD: \"Khoa CNTT – ĐH Mở TP.HCM\")\n  url      String // URL liên kết\n  order    Int     @default(0)\n  isActive Boolean @default(true)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@schema(\"public\")\n}\n\n// ╔══════════════════════════════════════════════════════════════╗\n// ║                    MEMBERS & AUTH                            ║\n// ╚══════════════════════════════════════════════════════════════╝\n\n/// Thành viên CLB - liên kết với Supabase Auth qua authId\n/// Mỗi thành viên tương ứng 1 email Google, đăng nhập qua Supabase Auth\nmodel Member {\n  id           String    @id @default(cuid())\n  authId       String    @unique // Supabase Auth User ID (from Google login)\n  email        String    @unique\n  password     String? // Password for email/password login\n  githubId     String?   @unique // GitHub User ID\n  githubEmail  String?   @unique // Email verified for GitHub login by admin\n  firstName    String // Họ\n  lastName     String // Tên\n  avatar       String? // URL ảnh đại diện trên Supabase Storage\n  coverImage   String? // URL ảnh bìa/cover profile\n  slug         String?   @unique // Custom profile slug (auto-gen từ email prefix, cho phép tùy chỉnh)\n  dob          DateTime? // Ngày sinh\n  showDob      Boolean   @default(true) // Hiện/ẩn ngày sinh trên trang thành viên\n  bio          String? // Giới thiệu bản thân\n  phone        String? // Số điện thoại\n  studentId    String? // Mã sinh viên (nếu có)\n  socials      Json?     @default(\"{}\") // {\"github\":\"konnn04\",\"facebook\":\"konnn04\",\"youtube\":\"...\"}\n  joinedClubAt DateTime? // Ngày tham gia CLB\n  leftClubAt   DateTime? // Ngày rời CLB (null = đang hoạt động)\n  webRole      WebRole   @default(GUEST) // Quyền hạn trên hệ thống web\n  isActive     Boolean   @default(true) // Trạng thái hoạt động\n  createdBy    String? // ID of admin who created this member (null = root/self-registered)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // --- Relations ---\n  clubRoles       ClubRole[] // Các vai trò trong CLB theo thời gian\n  authoredPosts   Post[]              @relation(\"PostAuthor\") // Bài viết đã tạo\n  reviewedPosts   Post[]              @relation(\"PostReviewer\") // Bài viết đã duyệt\n  postRevisions   PostRevision[] // Lịch sử chỉnh sửa bài viết\n  createdEvents   Event[]             @relation(\"EventCreator\") // Sự kiện đã tạo\n  organizedEvents EventOrganizer[] // Sự kiện tham gia tổ chức\n  achievements    AchievementMember[] // Thành tựu liên quan\n  projects        ProjectMember[] // Dự án tham gia\n\n  @@index([webRole])\n  @@index([isActive])\n  @@index([slug])\n  @@schema(\"public\")\n}\n\n// ╔══════════════════════════════════════════════════════════════╗\n// ║                    CLUB STRUCTURE                            ║\n// ╚══════════════════════════════════════════════════════════════╝\n\n/// Ban / Phòng trong CLB\n/// VD: Ban Lập trình, Ban Sự kiện & Hậu cần, Ban Truyền thông\nmodel Department {\n  id   String @id @default(cuid())\n  slug String @unique // \"programming\", \"events-logistics\", \"communication\"\n\n  nameVi        String   @default(\"\") // \"Ban Lập Trình\"\n  descriptionVi String? // Mô tả chức năng ban\n  missionsVi    String[] @default([]) // Các nhiệm vụ chính\n  linkLabelVi   String? // Nút xem chi tiết (VD: \"Xem các dự án\")\n\n  nameEn        String   @default(\"\") // \"Programming Dept\"\n  descriptionEn String?\n  missionsEn    String[] @default([])\n  linkLabelEn   String?\n\n  icon    String? // Mã icon Lucide (VD: \"Code\", \"Camera\")\n  bgImage String? // Đường dẫn ảnh nền (VD: \"/images/bg/lt.jpg\")\n\n  order    Int     @default(0) // Thứ tự hiển thị\n  isActive Boolean @default(true) // Có đang hoạt động không\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // --- Relations ---\n  clubRoles ClubRole[] // Các chức vụ thuộc ban\n\n  @@schema(\"public\")\n}\n\n/// Vai trò / Chức vụ của thành viên trong CLB (lịch sử chức vụ theo thời gian)\n/// Mỗi record = 1 giai đoạn giữ chức vụ. endAt = null nghĩa là đang đảm nhiệm.\n/// \n/// VD: Nguyễn Triều từng là:\n///   - Thành viên ban Lập trình (2022-2023)\n///   - Trưởng ban Lập trình (2023-2024)  \n///   - Chủ nhiệm CLB nhiệm kỳ 2024 (2024-now)\nmodel ClubRole {\n  id           String       @id @default(cuid())\n  memberId     String\n  departmentId String? // Null = vai trò cấp CLB (Chủ nhiệm, Phó CN, Cố vấn, CTV)\n  position     ClubPosition // Chức vụ\n  term         Int? // Nhiệm kỳ (VD: 2023, 2024) - dành cho chủ nhiệm, phó CN\n  note         String? // Ghi chú thêm\n  startAt      DateTime // Ngày bắt đầu đảm nhiệm\n  endAt        DateTime? // Ngày kết thúc (null = đang đảm nhiệm)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // --- Relations ---\n  member     Member      @relation(fields: [memberId], references: [id], onDelete: Cascade)\n  department Department? @relation(fields: [departmentId], references: [id], onDelete: SetNull)\n\n  @@index([memberId])\n  @@index([departmentId])\n  @@index([position])\n  @@index([startAt])\n  @@schema(\"public\")\n}\n\n// ╔══════════════════════════════════════════════════════════════╗\n// ║                   POSTS & CONTENT                           ║\n// ╚══════════════════════════════════════════════════════════════╝\n\n/// Danh mục bài viết\n/// VD: \"Tin tức\", \"Hướng dẫn\", \"Chia sẻ kinh nghiệm\", \"Thông báo\"\nmodel Category {\n  id          String  @id @default(cuid())\n  name        String // Tên danh mục\n  slug        String  @unique // URL-friendly identifier\n  description String? // Mô tả danh mục\n  color       String? // Mã màu hiển thị (VD: \"#3B82F6\")\n  order       Int     @default(0) // Thứ tự hiển thị\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // --- Relations ---\n  posts Post[]\n\n  @@schema(\"public\")\n}\n\n/// Thẻ tag - dùng chung cho bài viết và sự kiện\nmodel Tag {\n  id   String @id @default(cuid())\n  name String // Tên tag\n  slug String @unique // URL-friendly identifier\n\n  createdAt DateTime @default(now())\n\n  // --- Relations ---\n  posts  PostTag[]\n  events EventTag[]\n\n  @@schema(\"public\")\n}\n\n/// Bài viết / Blog post\n/// Workflow: DRAFT -> PENDING_REVIEW -> PUBLISHED (hoặc REJECTED)\n/// Member chỉ được tạo DRAFT và gửi PENDING_REVIEW\n/// Collaborator/Admin được PUBLISHED trực tiếp\nmodel Post {\n  id         String     @id @default(cuid())\n  title      String // Tiêu đề\n  slug       String     @unique // URL-friendly identifier\n  summary    String? // Tóm tắt nội dung\n  content    String // Nội dung chính (Markdown/HTML)\n  thumbnail  String? // Ảnh đại diện bài viết (Supabase Storage URL)\n  status     PostStatus @default(DRAFT) // Trạng thái bài viết\n  isPinned   Boolean    @default(false) // Ghim bài viết lên đầu\n  viewCount  Int        @default(0) // Số lượt xem\n  authorId   String // Người viết\n  reviewerId String? // Người duyệt bài\n  categoryId String? // Danh mục\n\n  publishedAt DateTime? // Thời điểm xuất bản\n  createdAt   DateTime  @default(now())\n  updatedAt   DateTime  @updatedAt\n\n  // --- Relations ---\n  author       Member         @relation(\"PostAuthor\", fields: [authorId], references: [id], onDelete: Cascade)\n  reviewer     Member?        @relation(\"PostReviewer\", fields: [reviewerId], references: [id], onDelete: SetNull)\n  category     Category?      @relation(fields: [categoryId], references: [id], onDelete: SetNull)\n  tags         PostTag[]\n  revisions    PostRevision[]\n  achievements Achievement[] // Thành tựu liên quan bài viết\n\n  @@index([authorId])\n  @@index([status])\n  @@index([publishedAt])\n  @@index([categoryId])\n  @@schema(\"public\")\n}\n\n/// Lịch sử chỉnh sửa bài viết - mỗi lần sửa lưu 1 bản snapshot\n/// Giúp theo dõi ai sửa gì, khi nào, và có thể rollback\nmodel PostRevision {\n  id       String @id @default(cuid())\n  postId   String\n  editorId String // Người chỉnh sửa\n\n  title    String // Tiêu đề tại thời điểm sửa\n  summary  String? // Tóm tắt tại thời điểm sửa\n  content  String // Nội dung tại thời điểm sửa\n  editNote String? // Lý do / ghi chú chỉnh sửa\n\n  createdAt DateTime @default(now())\n\n  // --- Relations ---\n  post   Post   @relation(fields: [postId], references: [id], onDelete: Cascade)\n  editor Member @relation(fields: [editorId], references: [id], onDelete: Cascade)\n\n  @@index([postId])\n  @@index([editorId])\n  @@schema(\"public\")\n}\n\n/// Bảng trung gian: Post <-> Tag (many-to-many)\nmodel PostTag {\n  postId String\n  tagId  String\n\n  post Post @relation(fields: [postId], references: [id], onDelete: Cascade)\n  tag  Tag  @relation(fields: [tagId], references: [id], onDelete: Cascade)\n\n  @@id([postId, tagId])\n  @@schema(\"public\")\n}\n\n// ╔══════════════════════════════════════════════════════════════╗\n// ║                        EVENTS                               ║\n// ╚══════════════════════════════════════════════════════════════╝\n\n/// Sự kiện CLB\n/// Lưu thông tin các hoạt động, workshop, seminar, cuộc thi,...\nmodel Event {\n  id           String      @id @default(cuid())\n  title        String // Tên sự kiện\n  slug         String      @unique // URL-friendly identifier\n  description  String? // Mô tả ngắn\n  content      String? // Nội dung chi tiết (Markdown/HTML)\n  thumbnail    String? // Ảnh bìa sự kiện (Supabase Storage URL)\n  images       String[]    @default([]) // Các ảnh sự kiện bổ sung\n  location     String? // Địa điểm tổ chức\n  maxAttendees Int? // Số người tham dự tối đa (null = không giới hạn)\n  status       EventStatus @default(UPCOMING) // Trạng thái sự kiện\n  type         EventType?  @default(OTHER) // Phân loại sự kiện\n  startAt      DateTime // Ngày giờ bắt đầu\n  endAt        DateTime? // Ngày giờ kết thúc\n  creatorId    String // Người tạo sự kiện\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // --- Relations ---\n  creator      Member             @relation(\"EventCreator\", fields: [creatorId], references: [id], onDelete: Cascade)\n  organizers   EventOrganizer[] // Ban tổ chức\n  tags         EventTag[] // Tags\n  sponsorships EventSponsorship[] // Tài trợ\n  gallery      EventGallery[] // Thư viện ảnh\n\n  @@index([status])\n  @@index([startAt])\n  @@index([creatorId])\n  @@schema(\"public\")\n}\n\n/// Thành viên ban tổ chức sự kiện\n/// Ghi nhận ai tham gia tổ chức sự kiện với vai trò gì\nmodel EventOrganizer {\n  id       String @id @default(cuid())\n  eventId  String\n  memberId String\n  role     String // VD: \"organizer\", \"speaker\", \"mc\", \"volunteer\", \"mentor\"\n\n  createdAt DateTime @default(now())\n\n  // --- Relations ---\n  event  Event  @relation(fields: [eventId], references: [id], onDelete: Cascade)\n  member Member @relation(fields: [memberId], references: [id], onDelete: Cascade)\n\n  @@unique([eventId, memberId]) // Mỗi người chỉ 1 vai trò / sự kiện\n  @@schema(\"public\")\n}\n\n/// Bảng trung gian: Event <-> Tag (many-to-many)\nmodel EventTag {\n  eventId String\n  tagId   String\n\n  event Event @relation(fields: [eventId], references: [id], onDelete: Cascade)\n  tag   Tag   @relation(fields: [tagId], references: [id], onDelete: Cascade)\n\n  @@id([eventId, tagId])\n  @@schema(\"public\")\n}\n\n/// Thư viện ảnh sự kiện\n/// Lưu các ảnh recap, highlight của sự kiện\nmodel EventGallery {\n  id      String  @id @default(cuid())\n  eventId String\n  url     String // URL ảnh trên Supabase Storage\n  caption String? // Chú thích ảnh\n  order   Int     @default(0) // Thứ tự hiển thị\n\n  createdAt DateTime @default(now())\n\n  // --- Relations ---\n  event Event @relation(fields: [eventId], references: [id], onDelete: Cascade)\n\n  @@index([eventId])\n  @@schema(\"public\")\n}\n\n// ╔══════════════════════════════════════════════════════════════╗\n// ║                     ACTIVITIES                              ║\n// ╚══════════════════════════════════════════════════════════════╝\n\n/// Hoạt động CLB (Thay thế cho events.json data)\n/// Gồm các loại hoạt động/chương trình của CLB\nmodel Activity {\n  id   String @id @default(cuid())\n  slug String @unique\n\n  titleVi       String\n  descriptionVi String?\n\n  titleEn       String?\n  descriptionEn String?\n\n  hyperlink String? // Nút bấm chuyển tiếp (vd: /activities/webdesign)\n  thumbnail String? // Ảnh đại diện\n  images    String[] @default([]) // Danh sách các ảnh bổ sung (vd: từ imageFolder trước đây)\n\n  isInternal Boolean @default(false) // Phân biệt nội bộ hay bên ngoài\n  isActive   Boolean @default(true) // Có đang hiển thị không\n  order      Int     @default(0) // Thứ tự hiển thị\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@schema(\"public\")\n}\n\n// ╔══════════════════════════════════════════════════════════════╗\n// ║                  SPONSORS & PARTNERS                        ║\n// ╚══════════════════════════════════════════════════════════════╝\n\n/// Nhà tài trợ / Đối tác / Nhà đồng hành\n/// Lưu thông tin cơ bản của đơn vị tài trợ\nmodel Sponsor {\n  id          String  @id @default(cuid())\n  name        String // Tên nhà tài trợ / đối tác\n  slug        String  @unique // URL-friendly identifier\n  logo        String? // URL logo (Supabase Storage)\n  email       String? // Email liên hệ\n  phone       String? // SĐT liên hệ\n  website     String? // Website\n  description String? // Mô tả về nhà tài trợ\n  isActive    Boolean @default(true) // Đang hợp tác hay không\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // --- Relations ---\n  sponsorships EventSponsorship[] // Các đợt tài trợ\n\n  @@schema(\"public\")\n}\n\n/// Chi tiết tài trợ - liên kết Sponsor với Event hoặc CLB\n/// eventId = null: Tài trợ chung cho CLB\n/// eventId != null: Tài trợ cho sự kiện cụ thể\nmodel EventSponsorship {\n  id        String  @id @default(cuid())\n  sponsorId String\n  eventId   String? // Null = tài trợ chung cho CLB, không gắn sự kiện cụ thể\n\n  title   String? // Tên gói tài trợ (VD: \"Nhà tài trợ Kim cương\")\n  content String? // Chi tiết nội dung tài trợ\n  tier    String? // Hạng tài trợ: \"diamond\", \"gold\", \"silver\", \"bronze\"\n  amount  Decimal? // Giá trị tài trợ (nếu muốn lưu)\n\n  startAt DateTime // Ngày bắt đầu tài trợ\n  endAt   DateTime? // Ngày kết thúc tài trợ\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // --- Relations ---\n  sponsor Sponsor @relation(fields: [sponsorId], references: [id], onDelete: Cascade)\n  event   Event?  @relation(fields: [eventId], references: [id], onDelete: SetNull)\n\n  @@index([sponsorId])\n  @@index([eventId])\n  @@schema(\"public\")\n}\n\n// ╔══════════════════════════════════════════════════════════════╗\n// ║                      ACHIEVEMENTS                           ║\n// ╚══════════════════════════════════════════════════════════════╝\n\n/// Thành tựu CLB - giải thưởng, thành tích cá nhân/nhóm/CLB\nmodel Achievement {\n  id          String          @id @default(cuid())\n  title       String // Tên thành tựu\n  slug        String          @unique\n  summary     String? // Tóm tắt hiển thị trên card\n  content     String? // Chi tiết Markdown\n  thumbnail   String? // Ảnh card (Supabase Storage)\n  images      String[]        @default([]) // Các ảnh bổ sung\n  date        DateTime // Ngày đạt được\n  type        AchievementType @default(TEAM)\n  isHighlight Boolean         @default(false) // Nổi bật trang chủ\n\n  relatedUrl    String? // Link ngoài (bài báo, giải)\n  relatedPostId String? // Link bài viết nội bộ\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // --- Relations ---\n  relatedPost Post?               @relation(fields: [relatedPostId], references: [id], onDelete: SetNull)\n  members     AchievementMember[]\n\n  @@index([type])\n  @@index([date])\n  @@schema(\"public\")\n}\n\n/// Thành viên liên quan đến thành tựu (cá nhân thi, mentor, trưởng nhóm...)\nmodel AchievementMember {\n  achievementId String\n  memberId      String\n  role          String? // \"Thí sinh\", \"Mentor\", \"Trưởng nhóm\"\n\n  achievement Achievement @relation(fields: [achievementId], references: [id], onDelete: Cascade)\n  member      Member      @relation(fields: [memberId], references: [id], onDelete: Cascade)\n\n  @@id([achievementId, memberId])\n  @@schema(\"public\")\n}\n\n// ╔══════════════════════════════════════════════════════════════╗\n// ║                        PROJECTS                             ║\n// ╚══════════════════════════════════════════════════════════════╝\n\n/// Dự án CLB - showcase các sản phẩm của thành viên\nmodel Project {\n  id           String    @id @default(cuid())\n  title        String // Tên dự án\n  slug         String    @unique\n  description  String? // Mô tả ngắn\n  content      String? // Markdown chi tiết\n  thumbnail    String? // Supabase Storage\n  images       String[]  @default([]) // Các ảnh dự án bổ sung\n  githubUrl    String? // Link GitHub\n  websiteUrl   String? // Link demo/website\n  videoUrl     String? // YouTube embed URL\n  technologies Json      @default(\"[]\") // [\"Next.js\", \"React\", \"TypeScript\"]\n  startDate    DateTime?\n  endDate      DateTime?\n  isActive     Boolean   @default(true)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // --- Relations ---\n  members ProjectMember[]\n\n  @@schema(\"public\")\n}\n\n/// Thành viên tham gia dự án\nmodel ProjectMember {\n  projectId String\n  memberId  String\n  role      String? // \"Lead\", \"Developer\", \"Designer\"\n\n  project Project @relation(fields: [projectId], references: [id], onDelete: Cascade)\n  member  Member  @relation(fields: [memberId], references: [id], onDelete: Cascade)\n\n  @@id([projectId, memberId])\n  @@schema(\"public\")\n}\n\n// ╔══════════════════════════════════════════════════════════════╗\n// ║                      YEAR RECAP                             ║\n// ╚══════════════════════════════════════════════════════════════╝\n\n/// Tổng kết hoạt động CLB theo năm\n/// Dữ liệu recap được lưu dạng JSON tổng hợp từ Events, Achievements, Projects\nmodel YearRecap {\n  year        Int     @id // PK = năm (2024, 2025...)\n  name        String // Tên recap (VD: \"MPC Recap 2024\")\n  description String? // Mô tả\n  coverImage  String? // Ảnh bìa chào (slide 1)\n  coverImage2 String? // Ảnh bìa thông số (slide 2)\n  coverImage3 String? // Ảnh bìa \"bể cá\" thành viên mới (slide 3)\n  endImage    String? // Ảnh bìa kết thúc (slide cuối)\n  musicUrl    String? // URL nhạc nền (Supabase Storage)\n  data        Json?   @default(\"{}\") // JSON tổng hợp recap\n  isPublished Boolean @default(false)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@schema(\"public\")\n}\n",
  "runtimeDataModel": {
    "models": {},
    "enums": {},
    "types": {}
  },
  "parameterizationSchema": {
    "strings": [],
    "graph": ""
  }
}

